import{_ as d,o,c as t,a3 as a}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Branded module — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Branded module — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/branded"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Branded module — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/branded"}]]},"headers":[],"relativePath":"developer-guide/branded.md","filePath":"developer-guide/branded.md","lastUpdated":1784905729000}'),n={name:"developer-guide/branded.md"};function r(i,e,c,l,s,m){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="branded-module-—-developer-guide" tabindex="-1">Branded module — Developer Guide <a class="header-anchor" href="#branded-module-—-developer-guide" aria-label="Permalink to &quot;Branded module — Developer Guide&quot;">​</a></h1><p>Billable marketplace module (<code>slug: branded</code>, not default-included). Licensing: <code>module:branded</code>. Permissions: <code>branded.view</code>, <code>branded.manage</code>.</p><h2 id="domain-model" tabindex="-1">Domain model <a class="header-anchor" href="#domain-model" aria-label="Permalink to &quot;Domain model&quot;">​</a></h2><p>Stancl <code>domains</code> rows:</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>type</code></td><td><code>platform</code> | <code>custom</code></td></tr><tr><td><code>verification_token</code></td><td>TXT ownership token</td></tr><tr><td><code>verified_at</code></td><td>Set after DNS verify</td></tr><tr><td><code>is_primary</code></td><td>Preferred custom host for frontend links</td></tr><tr><td><code>claimed_at</code></td><td>Unverified claim TTL (<code>branded.claim_ttl_hours</code>)</td></tr></tbody></table><p><code>PlatformDomainClassifier</code> treats <code>{label}.{suffix}</code> under <code>config(&#39;branded.platform_domain_suffixes&#39;)</code> as platform. Everything else (including <code>myai.com.pk</code>, <code>app.domain.co.uk</code>) is custom — no two-label TLD assumption.</p><h2 id="resolution-gate" tabindex="-1">Resolution gate <a class="header-anchor" href="#resolution-gate" aria-label="Permalink to &quot;Resolution gate&quot;">​</a></h2><p><code>WorkspaceResolver::resolveFromHost</code>:</p><ul><li>Platform domains → always bind</li><li>Custom domains → only when <code>verified_at</code> is set <strong>and</strong> <code>EntitlementService::hasModule($tenant, &#39;branded&#39;)</code></li></ul><p>Pointing DNS/IP without a verified entitled row does nothing.</p><h2 id="tenant-api" tabindex="-1">Tenant API <a class="header-anchor" href="#tenant-api" aria-label="Permalink to &quot;Tenant API&quot;">​</a></h2><p>Prefix <code>/api/tenant/v1</code>, middleware <code>module:branded</code> + Spatie <code>can:</code>:</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th></tr></thead><tbody><tr><td>GET</td><td><code>/branded/domain</code></td><td><code>branded.view</code></td></tr><tr><td>POST</td><td><code>/branded/domain</code></td><td><code>branded.manage</code></td></tr><tr><td>POST</td><td><code>/branded/domain/verify</code></td><td><code>branded.manage</code></td></tr><tr><td>DELETE</td><td><code>/branded/domain</code></td><td><code>branded.manage</code></td></tr></tbody></table><p>Service: <code>App\\Services\\Tenant\\BrandedDomainService</code>. DNS via <code>App\\Contracts\\DomainDnsLookup</code> (<code>DnsGetRecordLookup</code> / <code>FakeDomainDnsLookup</code> in tests).</p><p>Central <code>TenantService</code> may only set <strong>platform</strong> hostnames.</p><h2 id="brand-chrome" tabindex="-1">Brand chrome <a class="header-anchor" href="#brand-chrome" aria-label="Permalink to &quot;Brand chrome&quot;">​</a></h2><ul><li><code>App\\Support\\BrandedMail::apply()</code> on tenant mail notifications</li><li>Published <code>resources/views/vendor/mail/html/message.blade.php</code> (+ button) for logo / brand name</li><li><code>EmailConfigResolver</code> overrides From name when branded is active</li><li><code>PlatformNotificationPayloadMapper</code> uses tenant logo/favicon + title prefix</li></ul><h2 id="cancel-deactivate" tabindex="-1">Cancel / deactivate <a class="header-anchor" href="#cancel-deactivate" aria-label="Permalink to &quot;Cancel / deactivate&quot;">​</a></h2><p><code>ModuleSubscriptionService::cancel</code> / <code>deactivate</code> clears custom-domain verification when the module slug is <code>branded</code>.</p><h2 id="production-hardening" tabindex="-1">Production hardening <a class="header-anchor" href="#production-hardening" aria-label="Permalink to &quot;Production hardening&quot;">​</a></h2><ul><li>Custom domain rows are <strong>force-deleted</strong> on remove / stale claim expiry so the unique <code>domains.domain</code> index can be reclaimed.</li><li>Verify <strong>fails closed</strong> when <code>BRANDED_SERVER_IPV4</code> / <code>BRANDED_SERVER_IPV6</code> / <code>BRANDED_CNAME_TARGET</code> are all empty.</li><li><code>BrandedCustomDomainCors</code> allows API CORS only for Origins whose host is a verified + entitled custom domain.</li><li>Scheduler: <code>branded:expire-stale-domain-claims</code> hourly.</li></ul><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>Pest: <code>tests/Feature/Tenant/Branded/BrandedDomainTest.php</code>, <code>tests/Feature/Notifications/BrandedNotificationPayloadTest.php</code>, <code>tests/Unit/DomainRuleTest.php</code>, <code>tests/Unit/PlatformDomainClassifierTest.php</code></li><li>Playwright: <code>npm run test:e2e:branded</code> (Domain tab hidden without module)</li></ul>',23)])])}const h=d(n,[["render",r]]);export{u as __pageData,h as default};
